  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useHUD } from '../../hooks/use_hud';
 10→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 11→import { useNavigation } from '../../hooks/use_navigation';
 12→import { ActionPanel } from '../action_panel/action_panel';
 13→import type { DropdownSection } from '../action_panel/actions_dropdown';
 14→import { EmptyState } from '../empty_state/empty_state';
 15→import { HUDContainer } from '../hud/hud_container';
 16→import { Kbd } from '../kbd/kbd';
 17→import { SearchBar } from '../search_bar/search_bar';
 18→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 19→import { SearchDropdown } from '../search_bar/search_dropdown';
 20→import './emoji_picker_view.scss';
 21→
 22→const COLUMNS = 6;
 23→const RECENTLY_USED_KEY = 'emoji-picker-recent';
 24→const MAX_RECENT = 12;
 25→
 26→function CopyHUDIcon() {
 27→  return (
 28→    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
 29→      <path
 30→        d="M3.5 8.5L6.5 11.5L12.5 4.5"
 31→        stroke="currentColor"
 32→        strokeWidth="1.5"
 33→        strokeLinecap="round"
 34→        strokeLinejoin="round"
 35→      />
 36→    </svg>
 37→  );
 38→}
 39→
 40→function SearchEmptyIcon() {
 41→  return (
 42→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 43→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 44→      <line
 45→        x1="30"
 46→        y1="30"
 47→        x2="42"
 48→        y2="42"
 49→        stroke="currentColor"
 50→        strokeWidth="3"
 51→        strokeLinecap="round"
 52→      />
 53→    </svg>
 54→  );
 55→}
 56→
 57→function loadRecentEmojis(): string[] {
 58→  try {
 59→    const stored = localStorage.getItem(RECENTLY_USED_KEY);
 60→    if (!stored) return [];
 61→    const parsed: unknown = JSON.parse(stored);
 62→    if (!Array.isArray(parsed)) return [];
 63→    return parsed.filter((v): v is string => typeof v === 'string');
 64→  } catch {
 65→    return [];
 66→  }
 67→}
 68→
 69→function saveRecentEmojis(chars: string[]) {
 70→  try {
 71→    localStorage.setItem(RECENTLY_USED_KEY, JSON.stringify(chars));
 72→  } catch {
 73→  }
 74→}
 75→
 76→interface EmojiSection {
 77→  title: string;
 78→  emojis: EmojiEntry[];
 79→}
 80→
 81→const FILTER_SECTIONS: SearchDropdownSection[] = [
 82→  {
 83→    options: [
 84→      {
 85→        label: 'All',
 86→        value: 'all',
 87→      },
 88→    ],
 89→  },
 90→  {
 91→    title: 'Category',
 92→    options: EMOJI_CATEGORIES.map(c => ({
 93→      label: c.label,
 94→      value: c.value,
 95→    })),
 96→  },
 97→];
 98→
 99→export function EmojiPickerView() {
100→  const nav = useNavigation();
101→  const [query, setQuery] = useState('');
102→  const [filterValue, setFilterValue] = useState('all');
103→  const [activeIndex, setActiveIndex] = useState(0);
104→  const [actionsOpen, setActionsOpen] = useState(false);
105→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
106→  const { items: hudItems, show: showHUD } = useHUD();
107→  const containerRef = useRef<HTMLDivElement>(null);
108→
109→  const emojiLookup = useMemo(() => {
110→    const map = new Map<string, EmojiEntry>();
111→    for (const e of MOCK_EMOJIS) {
112→      map.set(e.char, e);
113→    }
114→    return map;
115→  }, []);
116→
117→  const recentEmojis = useMemo(
118→    () =>
119→      recentChars
120→        .map(char => emojiLookup.get(char))
121→        .filter((e): e is EmojiEntry => e !== undefined),
122→    [
123→      recentChars,
124→      emojiLookup,
125→    ],
126→  );
127→
128→  const filtered = useMemo(() => {
129→    let emojis = MOCK_EMOJIS;
130→    if (filterValue !== 'all') {
131→      emojis = emojis.filter(e => e.category === filterValue);
132→    }
133→    if (query) {
134→      const lower = query.toLowerCase();
135→      emojis = emojis.filter(
136→        e =>
137→          e.name.toLowerCase().includes(lower) ||
138→          e.keywords.some(k => k.includes(lower)) ||
139→          e.char === query,
140→      );
141→    }
142→    return emojis;
143→  }, [
144→    query,
145→    filterValue,
146→  ]);
147→
148→  const sections = useMemo(() => {
149→    const result: EmojiSection[] = [];
150→
151→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
152→      result.push({
153→        title: 'Recently Used',
154→        emojis: recentEmojis,
155→      });
156→    }
157→
158→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
159→    for (const emoji of filtered) {
160→      const existing = grouped.get(emoji.category);
161→      if (existing) {
162→        existing.push(emoji);
163→      } else {
164→        grouped.set(emoji.category, [emoji]);
165→      }
166→    }
167→
168→    for (const cat of EMOJI_CATEGORY_ORDER) {
169→      const items = grouped.get(cat);
170→      if (items && items.length > 0) {
171→        result.push({
172→          title: EMOJI_CATEGORY_LABELS[cat],
173→          emojis: items,
174→        });
175→      }
176→    }
177→
178→    return result;
179→  }, [
180→    filtered,
181→    query,
182→    filterValue,
183→    recentEmojis,
184→  ]);
185→
186→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
187→  const totalCount = flatEmojis.length;
188→
189→  useEffect(() => {
190→    if (totalCount === 0) {
191→      setActiveIndex(0);
192→    } else if (activeIndex >= totalCount) {
193→      setActiveIndex(totalCount - 1);
194→    }
195→  }, [
196→    totalCount,
197→    activeIndex,
198→  ]);
199→
200→  useEffect(() => {
201→    const container = containerRef.current;
202→    if (!container) return;
203→    const el = container.querySelector<HTMLElement>(
204→      `[data-emoji-index="${activeIndex}"]`,
205→    );
206→    el?.scrollIntoView({ block: 'nearest' });
207→  }, [activeIndex]);
208→
209→  const selectedEmoji = flatEmojis[activeIndex];
210→
211→  const addToRecent = useCallback((char: string) => {
212→    setRecentChars(prev => {
213→      const next = [
214→        char,
215→        ...prev.filter(c => c !== char),
216→      ].slice(0, MAX_RECENT);
217→      saveRecentEmojis(next);
218→      return next;
219→    });
220→  }, []);
221→
222→  const handleCopyEmoji = useCallback(
223→    (emoji?: EmojiEntry) => {
224→      const target = emoji ?? selectedEmoji;
225→      if (!target) return;
226→      navigator.clipboard.writeText(target.char).catch(() => {});
227→      setActionsOpen(false);
228→      addToRecent(target.char);
229→      showHUD({
230→        icon: <CopyHUDIcon />,
231→        title: `Copied ${target.char}`,
232→      });
233→    },
234→    [
235→      selectedEmoji,
236→      showHUD,
237→      addToRecent,
238→    ],
239→  );
240→
241→  const handleQueryChange = useCallback((value: string) => {
242→    setQuery(value);
243→    setActiveIndex(0);
244→    setActionsOpen(false);
245→  }, []);
246→
247→  const handleFilterChange = useCallback((value: string) => {
248→    setFilterValue(value);
249→    setActiveIndex(0);
250→  }, []);
251→
252→  const toggleActions = useCallback(() => {
253→    setActionsOpen(prev => !prev);
254→  }, []);
255→
256→  const closeActions = useCallback(() => {
257→    setActionsOpen(false);
258→  }, []);
259→
260→  useKeyboardShortcut(
261→    {
262→      key: 'k',
263→      meta: true,
264→    },
265→    toggleActions,
266→  );
267→  useKeyboardShortcut(
268→    {
269→      key: 'c',
270→      meta: true,
271→    },
272→    () => handleCopyEmoji(),
273→  );
274→
275→  useEffect(() => {
276→    function handleKeyDown(e: KeyboardEvent) {
277→      if (totalCount === 0) return;
278→      if (e.metaKey || e.ctrlKey || e.altKey) return;
279→
280→      const isTextInput =
281→        e.target instanceof HTMLInputElement ||
282→        e.target instanceof HTMLTextAreaElement;
283→
284→      switch (e.key) {
285→        case 'ArrowRight': {
286→          if (isTextInput) return;
287→          e.preventDefault();
288→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
289→          break;
290→        }
291→        case 'ArrowLeft': {
292→          if (isTextInput) return;
293→          e.preventDefault();
294→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
295→          break;
296→        }
297→        case 'ArrowDown': {
298→          e.preventDefault();
299→          setActiveIndex(prev => {
300→            const sectionInfo = getSectionInfo(prev);
301→            if (!sectionInfo) return prev;
