16→    margin-top: $space-2;
17→  }
18→}
19→
20→.emoji-picker__section-header {
21→  font-size: $font-sm;
22→  font-weight: $font-weight-medium;
23→  color: $text-600;
24→  letter-spacing: 0.1px;
