@use '../../styles/tokens' as *;

$emoji-grid-columns: 6;
$emoji-font-size: 28px;

.emoji-picker {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow-y: auto;
  padding: 0 $space-2 $space-2;
}

.emoji-picker__section {
  &:not(:first-child) {
    margin-top: $space-2;
  }
}

.emoji-picker__section-header {
  font-size: $font-sm;
  font-weight: $font-weight-medium;
  color: $text-600;
  letter-spacing: 0.1px;
  padding: $space-1 $space-2;
  line-height: 1;
}

.emoji-picker__grid {
  display: grid;
  grid-template-columns: repeat($emoji-grid-columns, 1fr);
  gap: $space-half;
}

.emoji-picker__cell {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  aspect-ratio: 1;
  font-size: $emoji-font-size;
  border-radius: $radius-md;
  cursor: pointer;
  border: 2px solid transparent;
  transition:
    background-color $transition-fast ease,
    border-color $transition-fast ease,
    transform $transition-fast ease;
  user-select: none;
  line-height: 1;
  padding: 0;
  background: none;

  &:hover {
    background-color: $color-surface-hover;
    transform: scale(1.1);
  }

  &--active {
    border-color: $color-accent;
    background-color: $color-surface-hover;
  }
}

